import{_ as a,o as s,c as e,ag as n}from"./chunks/framework.BZohXCq9.js";const o="/assets/create-world.CFDui52z.png",r="/assets/editor-overview.DzohcdGo.png",i="/assets/first-message.CR6iAi3E.png",l="/assets/lorebook-list.APyM_5pK.png",p="/assets/lorebook-entry-detail.D8F8Ua7u.png",d="/assets/variables.Buh-ASug.png",c="/assets/behaviors.CTHu1VQw.png",h="/assets/message-renderer.Cqz0onzQ.png",u="/assets/beginner-studio-renderer.CePjT7Kf.png",g="/assets/beginner-studio-renderer2.alWC32nC.png",b="/assets/assets.CCC803sZ.png",S=JSON.parse('{"title":"新手指南：认识编辑器","description":"","frontmatter":{},"headers":[],"relativePath":"creator-guide/01-beginner-guide.md","filePath":"creator-guide/01-beginner-guide.md","lastUpdated":null}'),m={name:"creator-guide/01-beginner-guide.md"};function q(A,t,k,v,I,f){return s(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="新手指南-认识编辑器" tabindex="-1">新手指南：认识编辑器 <a class="header-anchor" href="#新手指南-认识编辑器" aria-label="Permalink to &quot;新手指南：认识编辑器&quot;">​</a></h1><blockquote><p>这篇会带你把编辑器从头到尾逛一遍，搞清楚每个区域是干嘛的。看完之后你就知道&quot;我想做XX效果，该去哪里设置&quot;了。</p></blockquote><h2 id="进入编辑器" tabindex="-1">进入编辑器 <a class="header-anchor" href="#进入编辑器" aria-label="Permalink to &quot;进入编辑器&quot;">​</a></h2><p>在 Yumina 左侧导航栏点 <strong>创建（Create）</strong> 按钮，你会看到模板选择页面 <strong>创建新世界（Create New）</strong>。这里有几个起点可以选：</p><ul><li><strong>空白项目（Blank Project）</strong> — 从零开始，完全自由</li><li><strong>角色对话（Character Chat）</strong> — 做一个 1 对 1 的角色聊天</li><li><strong>世界模拟（World Simulation）</strong> — 构建有阵营、事件的完整世界</li><li><strong>渐进式冒险（Progressive Adventure）</strong> — 带属性、背包、任务的 RPG</li><li><strong>多人战役（Multiplayer Campaign）</strong> — 2-4 人 DnD 风格跑团</li><li><strong>导入世界（Import World）</strong> — 从 JSON 文件或角色卡导入</li></ul><p>新手建议选 <strong>空白项目（Blank Project）</strong>，选完直接进入编辑器。在编辑器顶部的输入框里给世界起个名字就行。</p><p><img src="'+o+'" alt=""></p><h2 id="编辑器长什么样" tabindex="-1">编辑器长什么样 <a class="header-anchor" href="#编辑器长什么样" aria-label="Permalink to &quot;编辑器长什么样&quot;">​</a></h2><p>进来之后，你会看到这样的界面：</p><p><img src="'+r+'" alt="编辑器主界面"></p><p>左边是导航栏，一共 8 个区域。别被数量吓到，我们一个一个来看 (•̀ᴗ•́)و</p><hr><h2 id="开场白-first-message" tabindex="-1">开场白（First Message） <a class="header-anchor" href="#开场白-first-message" aria-label="Permalink to &quot;开场白（First Message）&quot;">​</a></h2><p>这是玩家进入你的世界后看到的 <strong>第一条消息</strong>。还没等玩家说话，AI 就先开口了——这条就是开场白。</p><p>好的开场白应该做到两件事：</p><ol><li>让玩家知道自己在什么处境（&quot;你醒来发现自己在一个陌生的房间……&quot;）</li><li>给玩家一个行动的理由（&quot;门外传来了敲门声&quot;）</li></ol><p>点 <strong>添加开场白（Add Greeting）</strong> 按钮就能开始写。</p><p><img src="'+i+'" alt="开场白编辑界面"></p><div class="tip custom-block"><p class="custom-block-title">小贴士</p><p>一个世界可以有多条开场白。玩家进入后默认看到第一条，可以左右滑动（swipe）切换其他开场白。适合提供不同的开局场景让玩家选择。</p></div><hr><h2 id="词条-lorebook" tabindex="-1">词条（Lorebook） <a class="header-anchor" href="#词条-lorebook" aria-label="Permalink to &quot;词条（Lorebook）&quot;">​</a></h2><p>这是编辑器里你会花最多时间的地方。</p><p><strong>词条是你写给 AI 看的所有内容</strong>——角色人设、世界观设定、写作风格要求、示例对话、剧情线索……全都是词条。你可以把它理解成 AI 的&quot;剧本&quot;。</p><p><img src="'+l+'" alt="词条列表界面"></p><h3 id="四个分组" tabindex="-1">四个分组 <a class="header-anchor" href="#四个分组" aria-label="Permalink to &quot;四个分组&quot;">​</a></h3><p>左侧有四个分组，决定词条在提示词里的位置。创建词条时，在哪个分组下点 <strong>添加词条（+ Add Entry）</strong>，词条就属于哪个分组：</p><table tabindex="0"><thead><tr><th>分组</th><th>英文</th><th>作用</th></tr></thead><tbody><tr><td>预设区</td><td>PRESETS</td><td><strong>始终发送</strong>的核心设定（角色、世界观、风格）。AI 每次都能看到</td></tr><tr><td>示例区</td><td>EXAMPLES</td><td>示例对话，教 AI 怎么说话</td></tr><tr><td>聊天历史区</td><td>CHAT HISTORY</td><td><strong>关键词触发</strong>的词条——只有聊天中出现匹配关键词才会激活</td></tr><tr><td>后置区</td><td>POST</td><td>放在所有对话之后的兜底指令，AI 最后看到，印象最深</td></tr></tbody></table><h3 id="发送身份-send-as" tabindex="-1">发送身份（Send as） <a class="header-anchor" href="#发送身份-send-as" aria-label="Permalink to &quot;发送身份（Send as）&quot;">​</a></h3><p>每个词条都有一个 <strong>Send as</strong> 设置，决定 AI 怎么看待这段内容：</p><table tabindex="0"><thead><tr><th>选项</th><th>英文</th><th>什么意思</th></tr></thead><tbody><tr><td>指令</td><td>Instruction</td><td>AI 把这当成系统规则来遵守（最常用）</td></tr><tr><td>用户</td><td>User</td><td>AI 以为这是玩家说的话</td></tr><tr><td>AI</td><td>AI</td><td>AI 以为这是自己之前说过的话。写示例对话或 CoT 绕过时用</td></tr></tbody></table><h3 id="标签-tags" tabindex="-1">标签（Tags） <a class="header-anchor" href="#标签-tags" aria-label="Permalink to &quot;标签（Tags）&quot;">​</a></h3><p>用标签给词条分类：Characters（角色）、Plot（剧情）、Style（风格）、Example（示例）、Preset（预设），也可以点 <strong>+ New</strong> 创建自定义标签。标签纯粹是方便你自己管理，不影响词条的行为。</p><h3 id="关键词触发" tabindex="-1">关键词触发 <a class="header-anchor" href="#关键词触发" aria-label="Permalink to &quot;关键词触发&quot;">​</a></h3><p>词条不是每次都会发给 AI 的（AI 一次能读的内容量是有限的，全塞进去会装不下）。</p><ul><li><strong>PRESETS 分组</strong>的词条始终发送——核心设定放这里</li><li><strong>CHAT HISTORY 分组</strong>的词条用关键词触发——填一些关键词（Keywords），只有聊天中出现这些词才会激活</li></ul><p>比如你在 CHAT HISTORY 里写了一条关于&quot;黑市&quot;的设定，关键词填 <code>黑市</code>。只有玩家提到&quot;黑市&quot;的时候，这条内容才会被发给 AI。这样既不浪费 AI 的阅读量，又能保证 AI 在需要的时候拿到正确的信息。聪明吧 (≧▽≦)</p><h3 id="排序-position" tabindex="-1">排序（Position） <a class="header-anchor" href="#排序-position" aria-label="Permalink to &quot;排序（Position）&quot;">​</a></h3><p>数字越小，AI 越优先看到这条内容。如果你有一条特别重要的设定，给它一个小的数字（比如 0），AI 就会更重视它。</p><p><img src="'+p+'" alt="词条编辑详情"></p><div class="info custom-block"><p class="custom-block-title">详细参考</p><p>想深入了解词条的所有配置（模糊匹配、二级关键词、递归触发、条件触发等），看 → <a href="./03-entries-and-lorebook.html">词条与世界书</a></p></div><hr><h2 id="变量-variables" tabindex="-1">变量（Variables） <a class="header-anchor" href="#变量-variables" aria-label="Permalink to &quot;变量（Variables）&quot;">​</a></h2><p>变量是你世界的&quot;记忆&quot;。任何需要追踪的数据——生命值、金币、好感度、当前位置——都存在变量里。</p><p>点 <strong>添加变量（Add Variable）</strong> 按钮新建。每个变量需要填：显示名称（Display Name）、类型（Type）、默认值（Default Value）。</p><p><img src="'+d+'" alt="变量管理界面"></p><p>四种类型，各有用途：</p><table tabindex="0"><thead><tr><th>类型</th><th>存什么</th><th>举个栗子</th></tr></thead><tbody><tr><td>数字（Number）</td><td>数字</td><td>HP: 100, 金币: 500</td></tr><tr><td>文字（String）</td><td>文字</td><td>当前位置: &quot;森林&quot;</td></tr><tr><td>开关（Boolean）</td><td>是/否</td><td>有钥匙: 是</td></tr><tr><td>JSON（Object / Array）</td><td>复杂数据</td><td>背包: 剑、药水、地图</td></tr></tbody></table><p>变量创建好之后，引擎会自动教 AI 怎么修改它们——你不需要手动写格式说明。AI 会在回复末尾用类似 <code>[health: -10]</code> 的格式来更新状态，引擎检测到后自动执行。你要做的就是在每个变量的 <strong>行为规则（Behavior Rules）</strong> 里用大白话告诉 AI &quot;什么情况下该改这个变量&quot;，剩下的引擎全搞定。</p><div class="info custom-block"><p class="custom-block-title">详细参考</p><p>操作语法、嵌套路径、JSON变量的高级用法 → <a href="./04-variables.html">变量系统</a> 和 <a href="./05-directives-and-macros.html">AI 指令与宏</a></p></div><hr><h2 id="行为-behaviors" tabindex="-1">行为（Behaviors） <a class="header-anchor" href="#行为-behaviors" aria-label="Permalink to &quot;行为（Behaviors）&quot;">​</a></h2><p>行为是你世界的&quot;自动化管家&quot;。它让你实现这种效果：</p><ul><li>&quot;HP 降到 0 → 弹出通知&#39;你死了&#39;&quot;</li><li>&quot;每 3 回合 → 饥饿度 +1&quot;</li><li>&quot;玩家说了&#39;投降&#39; → 触发特殊结局&quot;</li><li>&quot;60 秒倒计时结束 → 炸弹爆炸&quot;</li></ul><p>点 <strong>添加行为（Add Behavior）</strong> 后，每条行为就三个部分：<strong>WHEN</strong>（什么时候触发）→ <strong>ONLY IF</strong>（条件满足吗，可选）→ <strong>DO</strong>（做什么）</p><p><img src="'+c+`" alt="行为编辑界面"></p><p>举个最简单的例子：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WHEN:    变量穿过阈值（Variable crosses threshold）— health 降到 0 以下</span></span>
<span class="line"><span>ONLY IF: （不填）</span></span>
<span class="line"><span>DO:      通知玩家（Show notification）— &quot;你死了&quot;，danger 样式</span></span></code></pre></div><p>不需要写代码，在编辑器里点点选选就能配好。</p><div class="info custom-block"><p class="custom-block-title">详细参考</p><p>所有触发器类型、动作类型、优先级和冷却机制 → <a href="./06-rules-engine.html">行为规则引擎</a></p></div><hr><h2 id="消息渲染器-message-renderer" tabindex="-1">消息渲染器（Message Renderer） <a class="header-anchor" href="#消息渲染器-message-renderer" aria-label="Permalink to &quot;消息渲染器（Message Renderer）&quot;">​</a></h2><p>默认情况下，AI 的回复就是一段普通文字。但你见过的那些很酷的世界——气泡对话、视觉小说画面、带血条和背包的游戏界面——都是通过这个区域实现的。</p><p><img src="`+h+`" alt="消息渲染器编辑"></p><p>这里有两个选项：</p><ul><li><strong>默认（Default (plain markdown)）</strong>：普通 Markdown，不需要任何设置</li><li><strong>自定义 TSX（Custom TSX）</strong>：用代码完全自定义消息的外观</li></ul><p>&quot;等等，代码？！我不会写代码啊&quot; ——别慌，应该没有人会真的自己手敲代码吧 (￣▽￣)ノ</p><p>你有两个方法让 AI 帮你搞定：</p><h3 id="方法一-用-yumina-内置的-studio-ai" tabindex="-1">方法一：用 Yumina 内置的 Studio AI <a class="header-anchor" href="#方法一-用-yumina-内置的-studio-ai" aria-label="Permalink to &quot;方法一：用 Yumina 内置的 Studio AI&quot;">​</a></h3><p>编辑器里点 <strong>进入 Studio（Enter Studio）</strong>，打开 <strong>AI Assistant</strong> 面板，直接用大白话告诉它你想要什么。比如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我改一下消息的显示方式。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我想要每条消息上面有一个暗色的状态栏，里面显示：</span></span>
<span class="line"><span>- 一个红色的血条，显示 health 变量，满血是 100</span></span>
<span class="line"><span>- 一个蓝色的蓝条，显示 mp 变量，满蓝是 50</span></span>
<span class="line"><span>- 右边用金色文字显示金币数量，读 gold 变量</span></span>
<span class="line"><span></span></span>
<span class="line"><span>状态栏背景用深灰色，带一点蓝色的发光边框，看起来有奇幻RPG的感觉。</span></span>
<span class="line"><span>状态栏下面正常显示AI的回复文字就行。</span></span></code></pre></div><p>AI 会生成代码，右边的 Canvas 面板实时预览效果。满意就点 <strong>批准（Approve）</strong>，不满意继续说&quot;血条再粗一点&quot;、&quot;加个角色等级显示&quot;。</p><p><img src="`+u+'" alt="Studio AI 生成渲染器"><img src="'+g+`" alt="Studio AI 生成渲染器"></p><h3 id="方法二-用外部-ai-claude、chatgpt-等" tabindex="-1">方法二：用外部 AI（Claude、ChatGPT 等） <a class="header-anchor" href="#方法二-用外部-ai-claude、chatgpt-等" aria-label="Permalink to &quot;方法二：用外部 AI（Claude、ChatGPT 等）&quot;">​</a></h3><p>把你想要的效果告诉外部 AI，但要多加一段 Yumina 的技术信息（因为外部 AI 不了解 Yumina），让它能写出对的代码，并且外部ai不能帮忙改variable，你需要先自己设置好对应的variable哦ヾ(•ω•\`)o。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我在用一个叫 Yumina 的AI互动平台做世界。帮我写一段代码，改变消息的显示方式。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我想要的效果：</span></span>
<span class="line"><span>每条消息上面有一个暗色的状态栏（深灰底色，蓝色发光边框，圆角），里面显示：</span></span>
<span class="line"><span>- 红色的血条，显示 health 变量，满血 100</span></span>
<span class="line"><span>- 蓝色的蓝条，显示 mp 变量，满蓝 50</span></span>
<span class="line"><span>- 金色文字显示金币数量，读 gold 变量</span></span>
<span class="line"><span>状态栏下面正常显示消息文字。整体奇幻RPG暗色风格。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>下面是 Yumina 的技术信息，你写代码的时候需要遵守这些规则：</span></span>
<span class="line"><span>- 代码格式是 TSX，用 export default function Renderer({ content, renderMarkdown }) { ... } 导出</span></span>
<span class="line"><span>- 用 useYumina() 可以拿到游戏变量，比如 useYumina().variables.health</span></span>
<span class="line"><span>- 平台内置了 YUI 组件库（不用 import 直接用），其中 YUI.StatBar 可以做血条</span></span>
<span class="line"><span>- 平台内置了 Icons 图标库（不用 import），比如 Icons.Coins 是金币图标</span></span>
<span class="line"><span>- renderMarkdown(content) 可以把文字渲染成带格式的 HTML</span></span>
<span class="line"><span>- 支持 Tailwind CSS 和 React hooks</span></span></code></pre></div><p>拿到代码后 → 编辑器 → 消息渲染器（Message Renderer）→ 自定义 TSX（Custom TSX）→ 粘贴 → 看到 <strong>编译状态：OK（Compile Status: OK）</strong> 就成功了。</p><div class="tip custom-block"><p class="custom-block-title">报错了怎么办</p><p>如果粘贴后底部显示红色错误信息，把错误信息原封不动发回给 AI 说&quot;这段代码报错了，帮我修一下&quot;就行。来回两三轮就能搞定 ∠( ᐛ 」∠)＿</p></div><p>Yumina 还内置了一套叫 <strong>YUI</strong> 的组件库（血条、对话框、物品格子、场景背景等），AI 生成代码的时候会自动用上这些。你不用了解这些组件怎么写，AI 知道就行了。</p><div class="tip custom-block"><p class="custom-block-title">Studio 是什么</p><p>Studio 是编辑器的&quot;进阶模式&quot;。除了 AI 助手，还有代码编辑器、实时预览、测试面板。点编辑器顶部的 <strong>进入 Studio（Enter Studio）</strong> 就能进去。后面的 <a href="./07-components.html">自定义前端指南</a> 会详细讲。</p></div><div class="info custom-block"><p class="custom-block-title">详细参考</p><p>完整的前端定制教学（更多示例 prompt、YUI 组件库、Studio 用法）→ <a href="./07-components.html">自定义前端指南</a> 渲染器技术细节和 API → <a href="./08-message-renderer.html">自定义消息渲染器</a></p></div><hr><h2 id="音频-audio" tabindex="-1">音频（Audio） <a class="header-anchor" href="#音频-audio" aria-label="Permalink to &quot;音频（Audio）&quot;">​</a></h2><p>给你的世界加上 BGM、音效和环境音。支持三种音频类型：</p><table tabindex="0"><thead><tr><th>类型</th><th>用途</th><th>例子</th></tr></thead><tbody><tr><td>BGM</td><td>背景音乐</td><td>主题曲、战斗音乐</td></tr><tr><td>SFX</td><td>音效</td><td>开门声、爆炸声</td></tr><tr><td>Ambient</td><td>环境音</td><td>雨声、人群嘈杂</td></tr></tbody></table><p>最简单的使用方法：先在 <strong>素材（Assets）</strong> 区域上传音频文件，然后在 <strong>音频（Audio）</strong> 区域点 <strong>添加音轨（Add Track）</strong>，选择音频来源，就可以使用了。</p><p>你可以设置：</p><ul><li>简单的循环播放</li><li>根据游戏状态自动切歌（比如进入战斗换成战斗 BGM）</li><li>让 AI 在回复中触发音效（<code>[audio: explosion play]</code>）</li></ul><div class="info custom-block"><p class="custom-block-title">详细参考</p><p>播放列表、条件 BGM、AI 音频指令 → <a href="./09-audio.html">音频系统</a></p></div><hr><h2 id="素材-assets" tabindex="-1">素材（Assets） <a class="header-anchor" href="#素材-assets" aria-label="Permalink to &quot;素材（Assets）&quot;">​</a></h2><p>上传图片和音频素材的地方。角色立绘、场景图、道具图标、BGM……传上来之后可以在渲染器或音频里引用。</p><p><img src="`+b+'" alt="素材管理界面"></p><hr><h2 id="概览-overview" tabindex="-1">概览（Overview） <a class="header-anchor" href="#概览-overview" aria-label="Permalink to &quot;概览（Overview）&quot;">​</a></h2><p>世界的&quot;个人信息页&quot;。在这里设置：</p><ul><li><strong>封面图（Cover Image）</strong> — 玩家在社区列表里第一眼看到的图</li><li><strong>画廊（Gallery Images）</strong> — 最多 8 张展示图</li><li><strong>描述（Description）</strong> — 详细介绍你的世界</li><li><strong>标签（Tags）</strong> — 帮助别人发现你的世界，最多 7 个</li><li><strong>公告（Announcement）</strong> — 置顶消息，适合写更新日志</li><li><strong>预计时长（Approx. Time）</strong> — 告诉玩家大概要玩多久</li><li><strong>语言（Language）</strong> — 设置你的世界的语言（支持中/英/日/韩等 10 种语言）</li><li><strong>多人模式（Allow Multiplayer）</strong> — 是否允许多人一起玩</li></ul><h3 id="多语言支持" tabindex="-1">多语言支持 <a class="header-anchor" href="#多语言支持" aria-label="Permalink to &quot;多语言支持&quot;">​</a></h3><p>设置了语言之后，会出现 <strong>语言变体（Language Variants）</strong> 区域。你可以把同一个世界的不同语言翻译版链接在一起——比如你做了一个中文版和一个英文版，把它们链起来之后，玩家在开始游戏时会看到语言切换标签页，可以选择自己喜欢的语言来玩。</p><p>操作方法：</p><ol><li>先给当前世界设置语言（比如 <code>中文</code>）</li><li>点 <strong>添加语言版本（Add Language Version）</strong></li><li>上传翻译版的世界 JSON 文件</li><li>选择翻译版的语言（比如 <code>English</code>）</li><li>导入后两个世界就自动链接了</li></ol><p>做完世界、测试没问题之后，回到 <strong>发现（Discover）</strong> 页面，点顶部的 <strong>发布（Publish）</strong> 按钮就能把世界上线。</p><div class="info custom-block"><p class="custom-block-title">详细参考</p><p>发布流程、Bundle 导出、多人模式、多语言支持 → <a href="./11-publish-and-share.html">发布、导出与 Bundle</a></p></div><hr><h2 id="测试你的世界" tabindex="-1">测试你的世界 <a class="header-anchor" href="#测试你的世界" aria-label="Permalink to &quot;测试你的世界&quot;">​</a></h2><p>编辑器左侧导航栏最底部有一个大大的金色 <strong>PLAY</strong> 按钮——点它就能开始测试。会弹出会话选择界面，点 <strong>新建会话（New Session）</strong> 就能进入你的世界开始玩了。</p><p>测试中觉得哪里不对？随时回编辑器改，改完点 <strong>保存（Save）</strong>，再 PLAY 一次。</p><hr><h2 id="引擎在背后做了什么" tabindex="-1">引擎在背后做了什么 <a class="header-anchor" href="#引擎在背后做了什么" aria-label="Permalink to &quot;引擎在背后做了什么&quot;">​</a></h2><p>好奇玩家发一条消息后，背后到底发生了什么？完整的流水线（词条→提示词→AI→指令→变量→规则→渲染）在 <a href="./01-core-concepts.html#运行流程">核心概念速览</a> 里有详细图解，这里不重复了。</p><p>一句话版本：引擎把词条组装成提示词发给 AI → AI 回复带指令 → 引擎提取指令更新变量 → 触发规则 → 渲染给玩家。每次发消息都跑一遍，玩家完全无感 ∠( ᐛ 」∠)＿</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>编辑器的每个角落你都认识了。接下来跟着 <a href="./02-tutorial-basic.html">手把手教程</a>，从零做一个完整的生存恐怖世界出来。做一遍比看十遍文档有用 ᕕ( ᐛ )ᕗ</p>',113)])])}const _=a(m,[["render",q]]);export{S as __pageData,_ as default};
